def min_truck_capacity(demand, max_refills):
    if not demand:
        return 0

    def can_deliver(capacity):
        refills = 0
        current_load = capacity
        for d in demand:
            if d > capacity:
                return False
            if current_load < d:
                refills += 1
                if refills > max_refills:
                    return False
                current_load = capacity
            current_load -= d
        return True

    lo = max(demand)
    hi = sum(demand)

    while lo < hi:
        mid = (lo + hi) // 2
        if can_deliver(mid):
            hi = mid
        else:
            lo = mid + 1

    return lo

