import unittest

class TestSolution(unittest.TestCase):
    def test_basic_example(self):
        self.assertEqual(min_truck_capacity([3, 5, 2, 7, 4], 1), 11)

    def test_single_store(self):
        self.assertEqual(min_truck_capacity([10], 0), 10)

    def test_max_refills_available(self):
        self.assertEqual(min_truck_capacity([1, 1, 1, 1, 1], 4), 1)

    def test_hidden_empty_demand(self):
        self.assertEqual(min_truck_capacity([], 5), 0)

    def test_hidden_no_refills_multiple_stores(self):
        self.assertEqual(min_truck_capacity([1, 1, 1, 1, 1], 0), 5)

    def test_hidden_equal_demands(self):
        self.assertEqual(min_truck_capacity([5, 5, 5, 5], 1), 10)

    def test_hidden_increasing_demands_no_refill(self):
        self.assertEqual(min_truck_capacity([100, 200, 300], 0), 600)

    def test_hidden_large_uniform(self):
        self.assertEqual(min_truck_capacity([1] * 10000, 9), 1000)

    def test_hidden_pi_digits(self):
        self.assertEqual(min_truck_capacity([3, 1, 4, 1, 5, 9, 2, 6], 2), 14)

    def test_hidden_single_large_store(self):
        self.assertEqual(min_truck_capacity([1000000], 0), 1000000)

    def test_hidden_two_stores_one_refill(self):
        self.assertEqual(min_truck_capacity([7, 8], 1), 8)

    def test_hidden_all_refills_needed(self):
        # 4 stores, 3 refills => each store gets its own batch
        self.assertEqual(min_truck_capacity([3, 7, 2, 5], 3), 7)

if __name__ == '__main__':
    unittest.main()
